import java.util.ArrayList;
import java.util.Arrays;
import java.util.HashMap;
import java.util.List;
import java.util.Map;

public class Solution {
    /**
     * Checks if a character is a lowercase letter.
     */
    private static boolean isLetter(char c) {
        return c >= 'a' && c <= 'z';
    }

    /**
     * Checks if a character is part of a potential word (letter or hyphen).
     */
    private static boolean isWordChar(char c) {
        return isLetter(c) || c == '-';
    }

    public static long[] solve(String[] chunks, String[] queries) {
        // Step 1: Form string s
        StringBuilder sb = new StringBuilder();
        for (String chunk : chunks) {
            sb.append(chunk);
        }
        String s = sb.toString();

        // Step 2: Identify all maximal valid words in s
        List<String> finalWordTokens = new ArrayList<>();
        int ptr = 0;
        while (ptr < s.length()) {
            if (!isWordChar(s.charAt(ptr))) {
                ptr++;
                continue;
            }

            // Start of a potential word segment (maximal sequence of word chars)
            int start = ptr;
            int end = ptr + 1;

            // Greedily find the maximal contiguous segment of word characters
            while (end < s.length() && isWordChar(s.charAt(end))) {
                end++;
            }
            String segment = s.substring(start, end);

            // Now, parse this maximal segment to find maximal *valid* words within it.
            // Since the problem states "It is not a part of some longer valid word," 
            // we are looking for the maximal contiguous substring within the segment that satisfies the internal hyphen rule.

            int k_seg = 0;
            while (k_seg < segment.length()) {
                int wordStart = k_seg;
                int wordEnd = k_seg + 1; // Exclusive end index for the current potential word

                // Extend wordEnd as long as the sequence remains valid
                while (wordEnd <= segment.length()) {
                    char currentChar = segment.charAt(wordEnd - 1);

                    if (isLetter(currentChar)) {
                        wordEnd++;
                    } else if (currentChar == '-') {
                        // Check hyphen validity: must be between two letters within the current potential word structure [wordStart, wordEnd]

                        // The character before the hyphen is at index wordEnd - 2
                        // The character after the hyphen is at index wordEnd (if it exists)

                        if (wordEnd - 2 >= wordStart && isLetter(segment.charAt(wordEnd - 2))) {
                            // Check next character only if it's within the segment boundary
                            if (wordEnd < segment.length() && isLetter(segment.charAt(wordEnd))) {
                                wordEnd++;
                            } else {
                                // Hyphen is at the end or followed by non-letter/non-word-char (which shouldn't happen in this segment)
                                // If it's the last character of the segment, and it's a hyphen, it's invalid unless it has a preceding letter.
                                // If wordEnd == segment.length(), and currentChar is '-', and it had a preceding letter, it's invalid 
                                // because it lacks a following letter.
                                break;
                            }
                        } else {
                            // Hyphen is either at the start (wordEnd-2 < wordStart) or preceded by non-letter/non-word-char
                            break;
                        }
                    } else {
                        // Should not happen within this segment
                        break;
                    }
                }

                String candidateWord = segment.substring(wordStart, wordEnd);

                // A valid word must not be empty
                if (candidateWord.length() > 0) {
                    // Check if the constructed candidate is indeed maximal in the sense that 
                    // if we could extend it, it would have been extended in the inner loop.
                    // Since the inner loop maximizes the sequence starting at wordStart, 
                    // this candidate *is* the maximal word starting at wordStart.
                    finalWordTokens.add(candidateWord);
                    k_seg = wordEnd; // Move k_seg past the found word
                } else {
                    // If no word starts at k_seg (e.g., a lone hyphen not surrounded by letters), skip one character
                    k_seg++;
                }
            }

            ptr = end; // Move to the next segment in s
        }


        // Step 3: Count queries against the token list
        Map<String, Long> queryCounts = new HashMap<>();
        for (String q : queries) {
            queryCounts.put(q, 0L);
        }

        for (String token : finalWordTokens) {
            if (queryCounts.containsKey(token)) {
                queryCounts.put(token, queryCounts.get(token) + 1);
            }
        }

        // Step 4: Build the result array
        long[] ans = new long[queries.length];
        for (int i = 0; i < queries.length; i++) {
            ans[i] = queryCounts.getOrDefault(queries[i], 0L);
        }

        return ans;
    }
}
