                        currentK++;
                    } else if (char_k == '-') {
                        // Check context in the current word being built
                        // Previous must be a letter
                        boolean prevCharOk = currentWord.length() > 0 && (currentWord.charAt(currentWord.length() - 1) >= 'a' && currentWord.charAt(currentWord.length() - 1) <= 'z');

                        // Next must be a letter
