public class Solution {
    public static long[] solve(String[] chunks, String[] queries) {
        String s = String.join("", chunks);
        int n = s.length();

        // Helper function to check if a character is a letter (a-z)
        java.util.function.Predicate<Character> isLetter = c -> c >= 'a' && c <= 'z';

        // Helper function to check if a character is a word character (letter or hyphen)
        java.util.function.Predicate<Character> isWordChar = c -> isLetter.test(c) || c == '-';

        // Step 1: Tokenize s into maximal valid words
        List<String> finalWordTokens = new ArrayList<>();
        int ptr = 0;
        while (ptr < n) {
            if (!isWordChar.test(s.charAt(ptr))) {
                ptr++;
                continue;
            }

            // Start of a maximal segment of word characters
            int start = ptr;
            int end = ptr + 1;
            while (end < n && isWordChar.test(s.charAt(end))) {
                end++;
            }
            String segment = s.substring(start, end);

            // Parse this maximal segment to find maximal valid words within it.
            // A word must be a maximal contiguous substring of letters/valid hyphens.

            int k_seg = 0;
            while (k_seg < segment.length()) {
                String currentWord = "";
                int currentK = k_seg;

                // Greedily build the maximal valid word starting at currentK
                while (currentK < segment.length()) {
                    char char_k = segment.charAt(currentK);

                    if (isLetter.test(char_k)) {
                        currentWord += char_k;
                        currentK++;
                    } else if (char_k == '-') {
                        // Check context in the current word being built (currentWord) and next character in segment

                        // 1. Check previous character: must be a letter (i.e., currentWord is not empty and last char was a letter)
                        boolean prevCharOk = currentWord.length() > 0 && isLetter.test(currentWord.charAt(currentWord.length() - 1));

                        // 2. Check next character in segment
                        boolean nextCharOk = currentK + 1 < segment.length() && isLetter.test(segment.charAt(currentK + 1));

                        if (prevCharOk && nextCharOk) {
                            currentWord += char_k;
                            currentK++;
                        } else {
                            // Invalid hyphen placement, the word ends just before this hyphen
                            break;
                        }
                    } else {
                        // Should not happen if segment was extracted correctly
                        break;
                    }
                }

                if (currentWord.length() > 0) {
                    // This is the maximal word starting at k_seg. Add it as a token.
                    finalWordTokens.add(currentWord);
                    // Advance k_seg past this entire word
                    k_seg += currentWord.length();
                } else {
                    // If no word starts here (e.g., a lone hyphen not surrounded by letters, or just a delimiter), skip one character
                    k_seg++;
                }
            }

            ptr = end; // Move to the next segment in s
        }

        // Step 2: Count queries against the token list
        Map<String, Integer> queryCounts = new HashMap<>();
        for (String q : queries) {
            queryCounts.put(q, 0);
        }

        for (String token : finalWordTokens) {
            if (queryCounts.containsKey(token)) {
                queryCounts.put(token, queryCounts.get(token) + 1);
            }
        }

        // Step 3: Format the results
        long[] results = new long[queries.length];
        for (int i = 0; i < queries.length; i++) {
            results[i] = queryCounts.getOrDefault(queries[i], 0);
        }

        return results;
    }
}
